<template>
    <section class="main-content">
       <loader :is-visible="isLoading"></loader>
           <div  id="divMainLeadData" v-cloak>
           <div class="row">
                   <div class="col-md-12 padding-t_8">
                       <div class="theme-primary partition-full">
                           <span class="p-name text-white">{{$t('ManageContracts')}}</span>                           
                       </div>
                   </div>
               </div>
               <div class="border p-3">
                   <Form  ref="form">
                       <dynamic-form lang="en" ref="StageForm" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit">
                       </dynamic-form>
                       <div class="col-lg-6">
                       <div class="py-2"><small><span class="text-danger">
                                   {{ $t('MandatoryString') }}</span></small>
                       </div>
                       </div>
                   </Form>
               </div>
           </div>
       </section>        
</template>
<script>
import ContractDataService from "../../../services/DataService";
export default {
    data(){
        return{
            isLoading:false,
            contractID: this.$route.params.id,
            userId:null,
            compnayId:null,
            FormSchema:[],
            ClientData: [],
            AddressList: [],
            clientId:null,
            ClientName:'',
            ContractAddress:'',
            parentId:null,
            appUrl : process.env.VUE_APP_DEFAULT_APP_URL,
            currencyId:null,
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success save",
                    text: "<i class='fa fa-save pr-2'></i>Submit",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.onCancel
                }
            ]
        }
    },
    created:async function(){
        var vm=this;
        this.clientId = this.$route.query.clientId;
        this.parentId= this.$route.query.parentId;
        this.userId= this.GetUserInfo.ID;
        this.companyId= this.GetUserInfo.CompanyId;
        await this.GetDefaultCurrency();
        if(this.clientId>0 ){
            var id=vm.contractID
            await this.GetClientDetailByClientId(this.$route.query.clientId);
            await this.getAdditionalAddressList();
        }
        this.FetchData();
    },
    methods:{
        GetDefaultCurrency: async function() {
            var vm = this
            await ContractDataService.GetConfigurationValueForCompanyByKey('key=Currency').then((response) => {
                if(response && response.data && response.data.length>0){
                    vm.currencyId = parseInt(response.data);
                }
            });
        },
        GetClientDetailByClientId: async function (val) {
            var vm = this;
            var params = `ClientId=${val}`;
            await ContractDataService.GetClientDetailByClientId(params).then(function (response) {
                if( response.data){
                vm.ClientData = response.data;
                vm.ClientName = response.data.clientdetail.first_name + ' ' + response.data.clientdetail.last_name;
            }
            });
        },
        async getAdditionalAddressList() {
            var vm = this;
            var url = `userId=${vm.clientId}&userAddressId=0`;
            await ContractDataService.GetAdditionalAddressList(url).then((response) => {
                if (response.data != null) {
                    vm.AddressList = [];
                    if (response.data.result.length > 0) {
                        vm.AddressList = response.data.result;
                        vm.AddressList.forEach(element => {
                            element.isSelected = false;
                        });
                        vm.ContractAddress=response.data.result[0].user_address_1;
                    }
                }

            });
        },
        onCancel: function () {
            var vm=this;
            if(vm.clientId){
                  vm.$router.push({path: `/Client/Update/${vm.clientId}/${vm.parentId}?redirectFrom=Contract`});
              }else{
                  vm.$router.push({ name: 'Contract' });
              }
        },
        onSearch: function (e, selctedValue, search) { 
            var vm = this;
            vm.searchSelectData(search, vm, selctedValue);
        },
        searchSelectData: function (search,ths, selctedValue) {
           
            this.ShowSearchData(search, ths, selctedValue);
        },       
        ShowSearchData: async function (search, ths,selctedValue) {            
            var vm = this;  
            var appendingUrl = `id=&&moduleName=CRM&type=ACCOUNTS&search=${search}&refId=`;
            if (typeof (selctedValue) == 'undefined') {
                selctedValue = 0;
            }
            selctedValue.config.options = []; 
            await ContractDataService.getDDLData(appendingUrl).then(function (response) {                
                if (response.data) {                    
                    vm.JsonObj = response.data;
                    if (vm.JsonObj != null) {
                        response.data.DATA.forEach((item) => {
                            var obj = {
                                value: item.value,
                                name: item.name
                            }                            
                            selctedValue.config.options.push(obj);                           
                        })
                        vm.$refs.StageForm.UpdateKeyValue();
                    }
                }
            });
        },
        FetchData:function(){
            var vm = this;
            vm.isLoading=true;
            const params = `recordId=${vm.$route.params.id}&moduleName=CRM&subModuleCode=CRM_CONTRACTS&langCode=en`;
            ContractDataService.GetDynamicForm(params)
                .then(function (response) {                     
                    vm.isLoading=false;
                    vm.FormSchema = vm.$refs.StageForm.ConvertCustomFieldIntoDynamicFormObj(response.data.data);      
                    vm.FormSchema.forEach((group, gi) => {
                        group.Data.forEach(async  (field, fi) => {
                            if (field.name == "account_id") {
                                field.config.onSearchChange = vm.onSearch;                                
                            } 
                            // if(field.name == "total_price"){
                            //     field.validationRules.decimal=true;
                            // }
                            // if(field.name == "billing_start_date" || field.name == "contract_start_date"){
                            //     field.config.minDate = new Date();
                            // }
                            if(field.name == "total_discount"){
                                field.validationRules.integer=true;
                            }
                            if(vm.clientId && field.name=='customer_id'){
                                var obj = field.config.options.filter(x=>x.value==vm.clientId)[0];
                                if(obj){
                                    field.value = {'label':obj.name,'value':obj.value}
                                    field.disabled = true;
                                }
                            }
                            if(vm.$route.params.id == 0 && vm.currencyId && field.name=='contract_currency'){
                                field.value = vm.currencyId;
                            }
                             if(field.name=="contract_name" && vm.contractID=='0' && vm.clientId>0){
                                field.value=  vm.ClientName;
                             }  
                             if(field.name=="contract_address" && vm.clientId>0){
                                field.value= field.value==''? vm.ContractAddress:field.value;
                             }
                             if((vm.$route.params.id == 0 || !field.value) && field.name == 'annual_price_increase'){
                                field.value = false;
                             }
                            field.config.onChange = vm.onChangeEventForFields;
                        })
                    })
                })
        },
        onChangeEventForFields: function (x, y, z) {
            var vm = this;
            if(y.name == "late_fee_id"){
                vm.$refs.StageForm.updateProperty("late_fee", "label", "Late Fee (%)");
                vm.$refs.StageForm.updateProperty("late_fee", "placeholder", "Enter Late Fee (%)");
            }
            else if(y.name == "billing_start_date"){                           
                vm.$refs.StageForm.updateProperty("billing_end_date", "config.minDate", x);
                vm.$refs.StageForm.UpdateKeyValue();                      
            } 
            else if(y.name == "contract_start_date"){                           
                vm.$refs.StageForm.updateProperty("contract_end_date", "config.minDate", x);
                vm.$refs.StageForm.UpdateKeyValue();                      
            } 
            else if(y.name == 'price_increase_detail_id'){
                 if(y.value == 'Fixed'){
                    vm.$refs.StageForm.updateProperty("price_increase", "label", `Price Increase ${vm.GetUserInfo.Currency}`);
                    vm.$refs.StageForm.updateProperty("price_increase", "placeholder", `Enter Price Increase ${vm.GetUserInfo.Currency}`);
                 }
                 else if(y.value == 'Percentage'){
                    vm.$refs.StageForm.updateProperty("price_increase", "label", "Price Increase (%)");
                    vm.$refs.StageForm.updateProperty("price_increase", "placeholder", "Enter Price Increase (%)");
                 }
                 else{
                    vm.$refs.StageForm.updateProperty("price_increase", "label", "Price Increase");
                    vm.$refs.StageForm.updateProperty("price_increase", "placeholder", "Enter Price Increase");
                 }
                 vm.$refs.StageForm.UpdateKeyValue();
            }
        },
        onSubmit(formfields, val) {
            var vm = this;
            vm.$refs.form.validate().then((result) => {
                if(result){
                    var CustomFieldArray = vm.$refs.StageForm.ConvertDynamicFormObjToCustomFieldObj(vm.FormSchema);
                    CustomFieldArray.forEach((x) => {
                        if (x.field_name == "created_by") {
                            x.field_value = vm.userId;
                        }
                        if (x.field_name == 'modified_by') {
                            x.field_value = vm.userId;
                        }
                        if (x.field_name == 'company_id') {
                            x.field_value = vm.companyId;
                        }
                        if (x.field_name == "account_id" || x.field_name == 'customer_id') {
                            if (!vm.isBlank(x.field_value)) {
                                x.field_value = x.field_value.value;
                            }
                        }
                        if (x.field_name == 'contract_id') {
                            x.field_value = vm.contractID;
                        }
                        if (x.field_name == 'created_at') {
                            x.field_value = vm.$options.filters.formatDate(new Date());
                        }
                        if (x.field_name == 'modified_at') {
                            x.field_value = vm.$options.filters.formatDate(new Date());
                        }    
                                       
                    });
                    var postJSON = {
                        data: CustomFieldArray
                    }
                    var objectPostString = JSON.stringify(postJSON);
                    ContractDataService.PostContract(objectPostString).then(response => {
                        vm.isLoading=false;
                        if (response.data[0].Code == "1") {
                            if (vm.contractID > 0) {
                                vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('Contract')]), "Success", true, vm.$t("Alert"));                                    
                            }
                            else {
                                vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Contract')]), "Success", true, vm.$t("Alert"));
                                                                     
                            }
                            if(vm.clientId){
                                // window.location.href = vm.appUrl + '/Client/Update?id=' + vm.clientId + '&reqFrom=Contract';
                                vm.$router.push({path: `/Client/Update/${vm.clientId}/${vm.parentId}?redirectFrom=Contract`});
                            }
                            else{
                                vm.$router.push({ name: 'Contract' });
                            }
                        }
                        else if (response.data[0].Code == "-1") {
                            vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('Contract')]), "warning", true, vm.$t("Alert"));                                
                        }
                        else {
                            vm.ShowAlert(vm.$t('AddedError', [vm.$t('Contract')]), "error", true, vm.$t("Alert"));                                 
                        }   
                    });
                }
            })
        }
    }
}
</script>